import { z } from "zod";

/**
 * Cross-link pass output schema (v1.5.3 §P2 — 2026-05-12 multi-pass consensus).
 *
 * The cross-link pass receives all pages generated by section-fill and
 * returns a list of `[[slug]]` insertion positions per page. It does NOT
 * modify body text. The service layer performs the actual insertion via
 * `body.slice(0, position) + linkText + body.slice(position)` — position-
 * based, NOT regex-based, so attacker-controlled prose cannot trigger an
 * unintended replacement.
 *
 * Position semantics:
 *  - 0-indexed character offset into the page body (JavaScript-string
 *    length, NOT byte offset; CJK characters count as 1).
 *  - Service rejects positions outside the valid range [0, body.length].
 *  - Service further rejects positions inside fenced code blocks, inline
 *    code, existing `[[...]]` links, existing `[text](url)` markdown
 *    links, and the Sources / 来源 section. (The skill prompt asks the
 *    model to avoid these zones, but the service double-checks.)
 *
 * surfaceText semantics:
 *  - If omitted, the link is rendered as `[[slug]]`.
 *  - If supplied, the link is rendered as `[[slug|surfaceText]]` — so a
 *    Chinese narrative can point at an ASCII-slugged English entity and
 *    still display naturally.
 *
 * Limits:
 *  - pages: ≤ 30 (matches ingestOutlineMaxPages default — one entry per
 *    page in the current diff session).
 *  - insertions: ≤ 50 per page. Empty arrays are normal and preferred
 *    over forced links.
 */

const SLUG_REGEX = /^[a-z0-9][a-z0-9-]{0,198}[a-z0-9]$/;

export const WikiCrosslinkInsertionSchema = z.object({
  position: z.number().int().min(0),
  linkSlug: z.string().regex(SLUG_REGEX),
  surfaceText: z.string().min(1).max(200).optional(),
});

export const WikiCrosslinkItemSchema = z.object({
  slug: z.string().regex(SLUG_REGEX),
  insertions: z.array(WikiCrosslinkInsertionSchema).max(50),
});

export const WikiCrosslinkSchema = z.object({
  pages: z.array(WikiCrosslinkItemSchema).max(30),
});

export type WikiCrosslink = z.infer<typeof WikiCrosslinkSchema>;
export type WikiCrosslinkItem = z.infer<typeof WikiCrosslinkItemSchema>;
export type WikiCrosslinkInsertion = z.infer<
  typeof WikiCrosslinkInsertionSchema
>;
